var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_PRIDE_NULL_NULL","text":{"KOREA":"고생 많으셨습니다. 구조 대상의 목숨에도 지장은 없다는군요.","JPN":"お疲れ様でした。救助対象も、命に別状はないとのことです。","ENG":"Thank you for your hard work. The rescue target is confirmed to be safe.","TWN":"辛苦了。據說救援物件的生命沒有危險。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"GUARD_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_PRIDE_NULL_NULL","text":{"KOREA":"혹시라도 의뢰비 정산을 원하신다면 제 쪽에서 문서 작성을 도와드리겠습니다.","JPN":"報酬の精算をご希望でしたら、こちらで書類の作成をお手伝いいたします。","ENG":"If you'd like to request payment, I can assist with the paperwork.","TWN":"如果你希望結算委託費用，我可以協助你準備相關檔。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"GUARD_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……딱히 돈을 바라고 한 일이 아니야. 기사의 사명대로 움직였을 뿐이다.","JPN":"……別に金目当てでやったことではない。騎士の使命どおり動いただけだ。","ENG":"...This wasn't about money. I acted as a knight should.","TWN":"……我並不是為了錢才做這件事的。我只是按照騎士的使命行事而已。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그것보다 부탁했던 건 어떻게 됐지?","JPN":"それより、頼んでいたものは？","ENG":"More importantly, what about the request I made?","TWN":"比起這個，我拜託你的事情怎麼樣了？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_PRIDE_NULL_NULL","text":{"KOREA":"그게… 난민지구에 평기사 분들의 치료를 원한다는 내용은 전달했습니다만.","JPN":"それが……難民地区に平騎士の方々の治療を希望する内容を伝えていますが。","ENG":"Well... I relayed the message about treating the knight bachelors in the refugee district.","TWN":"那個……我已經傳達了希望對難民區的平民騎士們進行治療的內容。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"GUARD_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_PRIDE_NULL_NULL","text":{"KOREA":"난민들의 반항이 거센 지라, 당장은 이렇다 할 방법이 없군요.","JPN":"難民たちの抵抗が激しく、現在はこれといった対策はありません。","ENG":"But tensions are high. There's no real way forward for now.","TWN":"難民們的反抗很激烈，目前還沒有什麼好的辦法。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"GUARD_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"대체 몇 번을 말해야 알아들어?","JPN":"何度も言わせるな！","ENG":"How many times do we have to say it?","TWN":"到底要再說多少遍才能聽懂？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"저 기사 침식체 놈들을 여기 들였다가 사상자라도 발생하면 당신네들이 책임질 거야?","JPN":"あの騎士の侵食体どもをここに入れて、死傷者が出たらあんたらが責任取ってくれるのか？","ENG":"If someone dies because you let those knight-C.O.s in here, will you take responsibility?","TWN":"要是把那些騎士侵蝕體引進來，導致出現傷亡的話，你們能負責嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"누가 기사 침식체야, 침식체는! 그게 도와준 사람한테 할 소리야?","JPN":"誰が騎士の侵食体よ！　助けてくれた人にそれはないでしょ！","ENG":"Knight-C.O.s?! We're not C.O.s! That's no way to talk to people who just saved you!","TWN":"誰是騎士侵蝕體啊！這是對幫助你的人該說的話嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"침착해요, 리브 경. 이런 일은 이제 익숙하잖아요.","JPN":"落ち着いてください、リブ卿。こんなこと初めてじゃないですし、慣れているじゃないですか。","ENG":"Calm down, Dame Liv. We're used to this by now.","TWN":"冷靜點，莉芙。這種事我們已經習慣了。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"익숙하긴 무슨. 도와준 사람한테 냅다 돌을 던지는 게 말이 돼?","JPN":"慣れるわけないでしょ。助けてくれた人に石投げるなんて、あり得ないよ！","ENG":"Used to this?! You call throwing rocks at your saviors normal?","TWN":"熟悉什麼啊。對幫助過你的人直接扔石頭，這說得過去嗎？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아저씨들이 침식체랑 싸우다 상처까지 입었는데 이건 너무하잖아!","JPN":"おじさんたちなんて侵食体と戦ったせいで怪我までしたのに、ひどすぎる！","ENG":"Those guys fought C.O.s and got hurt doing it. This is just cruel!","TWN":"叔叔們跟侵蝕體戰鬥還受了傷，這也太過分了吧！"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"전 괜찮습니다, 리브 경. 투구가 워낙 단단해서 이 정돈 생채기도 안 나요.","JPN":"私は大丈夫です、リブ卿。兜が丈夫ですから、これぐらいではかすり傷一つ負いませんよ。","ENG":"I'm fine, Dame Liv. My helmet's tough. There's barely even a scratch on it.","TWN":"我沒事，莉芙。頭盔非常堅固，這點小傷根本不算什麼。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"맞습니다. 민중을 수호하는 기사단이 그깟 돌팔매질에 당해서 되겠습니까?","JPN":"そうです。民衆を守護する騎士団は石ころごときに挫けたりはしません！","ENG":"Right. What kind of knights would we be if we couldn't take a few rocks?","TWN":"沒錯。守護民眾的騎士團怎麼會被那種小石子打敗呢？"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"장난으로 넘어가지 마! 그러다 상처가 덧나기라도 하면 어쩌려고 그래?","JPN":"ごまかさないで！　傷が悪化したらどうするの？","ENG":"Don't joke about it! What if the wounds get worse later?","TWN":"別拿這當玩笑！要是傷口惡化了怎麼辦？"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……단장님.","JPN":"……団長。","ENG":"...Captain.","TWN":"……團長。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경. 거기까지 하시죠. 난민분들이 두려워하고 계십니다.","JPN":"リブ卿、そこまでにしましょう。難民の方々が怯えています。","ENG":"Dame Liv, that's enough. You're scaring the refugees.","TWN":"莉芙。到此為止吧。難民們感到害怕了。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"마틴 경의 상처도 깊지 않아요. 본부에 돌아가도 늦지 않을 겁니다.","JPN":"マーティン卿の傷もそれほど深くありませんし、手当は本部に帰ってからでも遅くありません。","ENG":"Sir Martin's wounds aren't deep. He'll be fine once we return to HQ.","TWN":"馬丁的傷也不重。回總部也不遲。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장! 하지만…!!","JPN":"副団長！　でも……！！","ENG":"But Deputy...!!","TWN":"副團長！可是……！！"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"……미안. 좀 흥분했나 봐.","JPN":"……ごめん、ちょっと取り乱しすぎたね。","ENG":"...My apologies. I lost my temper.","TWN":"……抱歉。我好像有點激動了。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"동료의 부당함에 나서는 건 올바른 일입니다. 이번엔 그저, 감정에 치우쳤을 뿐이죠.","JPN":"仲間が不当な目に遭っている時に声を上げるのは、正しいことです。だだ今回は、感情に流されすぎただけです。","ENG":"Standing up for your comrades is noble. You just let your emotions get the better of you this time.","TWN":"為同伴的不公挺身而出是正確的事。這次只是有些感情用事罷了。"},"stage":{"bg":"CAMP_01","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님. 구조 의뢰는 끝마쳤으니 오늘은 이만 복귀하시죠.","JPN":"団長、救助依頼は済ませましたし、今日はここで帰還しましょう。","ENG":"Captain, the rescue mission is complete. Let's head back for today.","TWN":"團長，救援任務已經完成，今天就到此為止，回去吧。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……ああ。","ENG":"...All right.","TWN":"……是啊。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};